#include <iostream>
#include <cmath> 
using namespace std;
int n,a[1202],i=0;
int main(){
	cin>>n;
	int g=n;
	while(n!=1){
		i++;
		if(n%2==0){
			n/=2;
			a[i]=n;
		}else{
			n=n*3+1;
			a[i]=n;
		}
	}
	for(int k=i;k>=1;k--){
		cout<<a[k]<<' ';
	}
	cout<<g;
	return 0;
}
